import React from "react";

const Footer: React.FC = () => {
  return (
    <footer style={{ backgroundColor: "#006400", color: "#ffffff", padding: "20px 0" }}>
      <div className="container text-center">
        <h5>Contact Us</h5>
        <p>Email: <a href="mailto:manifestowatchindia@gmail.com" className="text-white text-decoration-none">manifestowatchindia@gmail.com</a></p>
        <p>Follow us on:</p>
        <p>
          <a href="https://twitter.com/ManifestoWatch" className="text-white text-decoration-none me-3">Twitter</a>
          <a href="https://www.instagram.com/ManifestoWatch" className="text-white text-decoration-none me-3">Instagram</a>
          <a href="https://www.youtube.com/ManifestoWatch" className="text-white text-decoration-none">YouTube</a>
        </p>
      </div>
    </footer>
  );
};

export default Footer;
